class Solution:
    def suggestedProducts(self, products, searchWord):
        # Brute force: for each prefix, filter and sort the full list each time.
        result = []
        for length in range(1, len(searchWord) + 1):
            prefix = searchWord[:length]
            matches = sorted(p for p in products if p.startswith(prefix))
            result.append(matches[:3])
        return result

