class Solution:
    def suggestedProducts(self, products, searchWord):
        import bisect
        products.sort()
        result = []
        prefix = ''
        lo = 0  # left boundary only moves right
        for ch in searchWord:
            prefix += ch
            lo = bisect.bisect_left(products, prefix, lo)
            group = []
            for i in range(lo, min(lo + 3, len(products))):
                if products[i].startswith(prefix):
                    group.append(products[i])
                else:
                    break
            result.append(group)
        return result

