var suggestedProducts = function(products, searchWord) {
    products.sort();
    const result = [];
    let prefix = '';
    let lo = 0;

    // Binary search: leftmost index >= target
    function lowerBound(arr, target, start) {
        let l = start, r = arr.length;
        while (l < r) {
            const mid = (l + r) >> 1;
            if (arr[mid] < target) l = mid + 1;
            else r = mid;
        }
        return l;
    }

    for (const ch of searchWord) {
        prefix += ch;
        lo = lowerBound(products, prefix, lo);
        const group = [];
        for (let i = lo; i < Math.min(lo + 3, products.length); i++) {
            if (products[i].startsWith(prefix)) group.push(products[i]);
            else break;
        }
        result.push(group);
    }
    return result;
};
